defmodule BankAccount do
  use GenServer

  # Client API

  def start_link(balance) do
    GenServer.start_link(__MODULE__, {:ok, balance}, name: __MODULE__)
  end

  def deposit(amount) do
    GenServer.call(__INFO__.server, {:deposit, amount})
  end

  def withdraw(amount) do
    GenServer.call(__INFO__.server, {:withdraw, amount})
  end

  def balance() do
    GenServer.call(__INFO__.server, :balance)
  end

  # Server Callbacks

