  def handle_call({:deposit, amount}, _from, ets) do
    validated_amount = validate_amount(amount)
    if validated_amount == :error do
      {:error, :invalid_amount}
    else
      updated_balance = Map.take(ets, self()) + validated_amount
      :ets.insert(ets, {self(), updated_balance})
      {:reply, updated_balance, ets}
    end
  end

  def handle_call({:withdraw, amount}, _from, ets) do
    validated_amount = validate_amount(amount)
    if validated_amount == :error do
      {:error, :invalid_amount}
    else
      balance = balance(ets) |> Map.get(self())
      case balance >= validated_amount do
        true ->
          updated_balance = Map.put(Map.take(ets, self()), balance - validated_amount)
          :ets.insert(ets, {self(), updated_balance})
          {:reply, updated_balance, ets}
        false -> {:error, :insufficient_funds}
      end
    end
  end

  def handle_call(:balance, _from, ets) do
    balance = Map.get(ets, self())
    {:reply, balance, ets}
  end

